mapper.select:
SELECT  
  FROM  TB_CNSLT_LIST A
 WHERE  A.CNSLT_ID = #{cnsltId}

mapper.insert:
INSERT  INTO TB_CNSLT_LIST
      ( CNSLT_ID
      , CNSLT_SJ
      , CNSLT_CN
      , OTHBC_AT
      , EMAIL_ADRES
      , EMAIL_ANSWER_AT
      , AREA_NO
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{cnsltId}
        , #{cnsltSj}
        , #{cnsltCn}
        , #{othbcAt}
        , #{emailAdres}
        , #{emailAnswerAt}
        , #{areaNo}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_CNSLT_LIST
   SET  LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  CNSLT_ID = #{cnsltId}

UPDATE  TB_CNSLT_LIST
   SET  CNSLT_SJ = #{cnsltSj}
      , CNSLT_CN = #{cnsltCn}
      , OTHBC_AT = #{othbcAt}
      , LAST_UPDUSR_ID = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  CNSLT_ID = #{cnsltId}
